checker_dsl:
EXISTS (`ConversionSite C`) {  
  EXISTS (`MulExpr E`) {  
    AND {  
      (`ConversionSite C is the result of applying getRestrictedParent zero or more times to MulExpr E`),  
      (`MulExpr E has type sourceType, ConversionSite C has conversion target type destType, destType is wider than sourceType, and destType is an IntegralType`),  
      (`ConversionSite C is not a trivial conversion and is an implicit conversion`),  
      NOT {  
        EXISTS (`NumType T`) {  
          EXISTS (`float LHS_BOUND`) {  
            EXISTS (`float RHS_BOUND`) {  
              EXISTS (`float PRODUCT`) {  
                AND {  
                  (`T is the type of MulExpr E`),  
                  (`LHS_BOUND is the bound of the left operand of MulExpr E`),  
                  (`RHS_BOUND is the bound of the right operand of MulExpr E`),  
                  (`PRODUCT equals LHS_BOUND multiplied by RHS_BOUND`),  
                  (`PRODUCT is less than or equal to the maximum value of the underlying primitive type of T`)  
                }  
              }  
            }  
          }  
        }  
      }  
    }  
  }  
}
